 747→        const finalImage = await sharp(baseLayer)
 748→            .composite(composites)
 749→            .jpeg({ quality: 82, mozjpeg: true })
 750→            .toBuffer();
 751→
 752→        setShareImageCached(`profile:${username}`, finalImage);
 753→        res.set('Content-Type', 'image/jpeg');
