407→router.get('/getUnreadNotification', requireAuth, async(req, res) => {
408→    const {before} = req.query;
409→
410→    const parsedLimit = parseLimitWithinRange(
411→        req.query.limit,
412→        NOTIFICATION_LIMIT_MIN,
413→        NOTIFICATION_LIMIT_MAX,
414→        NOTIFICATION_DEFAULT_LIMIT
415→    );
416→
417→    if(parsedLimit == null){
418→        return res.status(400).json({error: `limit must be between ${NOTIFICATION_LIMIT_MIN} and ${NOTIFICATION_LIMIT_MAX}`});
419→    }
420→
421→    const receiverId = req.userId;
422→    const fetchLimit = parsedLimit + 1;
423→
424→    let journalQuery = supabase
425→    .from('notifications')
426→    .select(NOTIFICATION_JOURNAL_SELECT)
427→    .eq('receiver_id', receiverId)
428→    .eq('read', false)
429→    .order('created_at', {ascending: false})
430→    .order('id', {ascending: false})
431→    .limit(fetchLimit)
432→
433→    let opinionQuery = supabase
434→    .from('notification_opinions')
435→    .select(NOTIFICATION_OPINION_SELECT)
436→    .eq('receiver_id', receiverId)
437→    .eq('read', false)
438→    .order('created_at', {ascending: false})
439→    .order('id', {ascending: false})
440→    .limit(fetchLimit)
441→
442→    if(before){
443→        journalQuery = journalQuery.lt('created_at', before);
444→        opinionQuery = opinionQuery.lt('created_at', before);
445→    }
446→
447→    const [journalResult, opinionResult] = await Promise.all([journalQuery, opinionQuery]);
448→
449→    if(journalResult.error){
450→        console.error('supabase error:', journalResult.error.message);
451→        return res.status(500).json({error: 'supabase error while getting unread notification'})
452→    }
453→    if(opinionResult.error){
454→        console.error('supabase error:', opinionResult.error.message);
455→        return res.status(500).json({error: 'supabase error while getting unread opinion notification'})
456→    }
457→
458→    const journalNotifs = (journalResult.data || []).map(n => ({...n, source: 'journal'}));
459→    const opinionNotifs = (opinionResult.data || []).map(n => ({...n, source: 'opinion'}));
460→
461→    const merged = [...journalNotifs, ...opinionNotifs]
462→        .sort((a, b) => new Date(b.created_at) - new Date(a.created_at));
463→
464→    const journalIds = [...new Set(
465→        merged
466→            .filter((n) => n.source === 'journal')
467→            .map((n) => n.journal_id)
468→            .filter(Boolean)
469→    )];
470→
471→    let hasLikedResult = [];
472→    let hasBookMarkedResult = [];
473→    if(journalIds.length > 0){
474→        const [hasLiked, hasBookMarked] = await Promise.all([
475→            supabase.from('likes').select('journal_id').eq('user_id', receiverId).in('journal_id', journalIds),
476→            supabase.from('bookmarks').select('journal_id').eq('user_id', receiverId).in('journal_id', journalIds)
477→        ]);
478→
479→        if(hasLiked.error || hasBookMarked.error){
480→            console.error('error', hasLiked.error || hasBookMarked.error)
481→            return res.status(500).json({error: 'supabase error on likes or bookmarks table'})
482→        }
483→        hasLikedResult = hasLiked.data || [];
484→        hasBookMarkedResult = hasBookMarked.data || [];
485→    }
486→
487→    const userHasLikedSet = new Set(hasLikedResult.map((like) => like.journal_id));
488→    const userHasBookmarkedSet = new Set(hasBookMarkedResult.map((bookmark) => bookmark.journal_id));
489→
490→    const formatted = merged.map((notification) => decorateNotificationMedia({
491→        ...notification,
492→        hasLiked: notification.source === 'journal' ? userHasLikedSet.has(notification?.journal_id) : false,
493→        hasBookMarked: notification.source === 'journal' ? userHasBookmarkedSet.has(notification?.journal_id) : false
494→    }))
495→
496→    const hasMore = formatted.length > parsedLimit;
497→    const slicedData = hasMore ? formatted.slice(0, parsedLimit) : formatted;
498→
499→    return res.status(200).json({
500→        data: slicedData,
501→        hasMore: hasMore
502→    })
503→})
