861→router.post('/update-username', requireAuth, async (req, res) => {
862→    const userId = req.userId;
863→    const { username } = req.body;
864→
865→    if (!username || typeof username !== 'string') {
866→        return res.status(400).json({ error: 'username is required' });
867→    }
868→
869→    const trimmed = username.trim();
870→    if (trimmed.length < 3 || trimmed.length > 50) {
871→        return res.status(400).json({ error: 'username must be 3-50 characters' });
872→    }
873→
874→    if (!/^[a-z0-9](?:[a-z0-9]*(?:-[a-z0-9]+)*)?$/.test(trimmed.toLowerCase())) {
875→        return res.status(400).json({ error: 'username must start/end with a letter or number and cannot have consecutive hyphens' });
876→    }
877→
878→    const normalized = trimmed.toLowerCase();
879→    const RESERVED_WORDS = ['admin', 'root', 'iskrib', 'iskryb', 'support', 'help', 'api', 'www', 'null', 'undefined'];
880→    if (RESERVED_WORDS.includes(normalized)) {
881→        return res.status(400).json({ error: 'this username is reserved' });
882→    }
883→
884→    // Check uniqueness
885→    const { data: existing } = await supabase
886→        .from('users')
887→        .select('id')
888→        .ilike('username', normalized)
889→        .neq('id', userId)
890→        .limit(1);
891→
892→    if (existing && existing.length > 0) {
893→        return res.status(409).json({ error: 'username is already taken' });
894→    }
895→
896→    const { error: updateError } = await supabase
897→        .from('users')
898→        .update({ username: trimmed.toLowerCase() })
899→        .eq('id', userId);
900→
901→    if (updateError) {
902→        console.error('update-username error:', updateError.message);
903→        return res.status(500).json({ error: 'failed to update username' });
904→    }
905→
