router.get('/getFollowsData', optionalAuth, async(req, res) => {
    const UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
    const {userId} = req.query;
    const loggedInUserId = req.userId || null;

    if(!userId || !UUID_RE.test(userId)) return res.status(400).json({error: 'valid userId is required'});

    try {
        const followersCountPromise = supabase
        .from('follows')
        .select('id', {count: 'exact', head: true})
        .eq('following_id', userId);

        const followingCountPromise = supabase
        .from('follows')
        .select('id', {count: 'exact', head: true})
        .eq('follower_id', userId)

        const promises = [followersCountPromise, followingCountPromise];

        if(loggedInUserId && UUID_RE.test(loggedInUserId)){
            promises.push(
                supabase
                .from('follows')
                .select('id', {count: 'exact', head: true})
                .eq('follower_id', loggedInUserId)
                .eq('following_id', userId)
            );
        }

        const results = await Promise.all(promises);

        const {count: followersCount, error: errorFollowers } = results[0];
        const {count: followingsCount, error: errorFollowings} = results[1];
        const isFollowingResult = results[2];
        const errorIsfollowing = isFollowingResult?.error;
        const isFollowingCount = isFollowingResult?.count ?? 0;

        if(errorFollowers || errorFollowings || errorIsfollowing){
            console.error('supabase error while fetching data:', errorFollowers?.message, errorFollowings?.message, errorIsfollowing?.message)
            return res.status(500).json({error: 'failed to fetch data'})
        }

        return res.status(200).json({
            followersCount: followersCount,
            followingsCount: followingsCount,
            isFollowing: isFollowingCount > 0
        })

    } catch (error) {
        console.error('Error in Promise.all:', error);
        res.status(500).json({ error: 'An unexpected error occurred' });
    }

})

router.get('/getCountNotifications', requireAuth, async(req, res) =>{
    const userId = req.userId;
