209→
210→    if(!userId || !UUID_RE.test(userId)) return res.status(400).json({error: 'valid userId is required'});
211→
212→    try {
213→        const followersCountPromise = supabase
214→        .from('follows')
215→        .select('id', {count: 'exact', head: true})
216→        .eq('following_id', userId);
217→
218→        const followingCountPromise = supabase
219→        .from('follows')
220→        .select('id', {count: 'exact', head: true})
221→        .eq('follower_id', userId)
222→
223→        const promises = [followersCountPromise, followingCountPromise];
224→
225→        if(loggedInUserId && UUID_RE.test(loggedInUserId)){
226→            promises.push(
227→                supabase
228→                .from('follows')
229→                .select('id', {count: 'exact', head: true})
230→                .eq('follower_id', loggedInUserId)
231→                .eq('following_id', userId)
232→            );
233→        }
234→
235→        const results = await Promise.all(promises);
236→
237→        const {count: followersCount, error: errorFollowers } = results[0];
238→        const {count: followingsCount, error: errorFollowings} = results[1];
239→        const isFollowingResult = results[2];
240→        const errorIsfollowing = isFollowingResult?.error;
241→        const isFollowingCount = isFollowingResult?.count ?? 0;
242→
243→        if(errorFollowers || errorFollowings || errorIsfollowing){
244→            console.error('supabase error while fetching data:', errorFollowers?.message, errorFollowings?.message, errorIsfollowing?.message)
245→            return res.status(500).json({error: 'failed to fetch data'})
246→        }
247→
248→        return res.status(200).json({
249→            followersCount: followersCount,
250→            followingsCount: followingsCount,
251→            isFollowing: isFollowingCount > 0
252→        })
253→
254→    } catch (error) {
