286→router.get('/getNotifications', requireAuth, async(req, res) =>{
287→    const {before} = req.query;
288→    const userId = req.userId;
289→    const parsedLimit = parseLimitWithinRange(
290→        req.query.limit,
291→        NOTIFICATION_LIMIT_MIN,
292→        NOTIFICATION_LIMIT_MAX,
293→        NOTIFICATION_DEFAULT_LIMIT
294→    );
295→
296→    if(parsedLimit == null){
297→        return res.status(400).json({error: `limit must be between ${NOTIFICATION_LIMIT_MIN} and ${NOTIFICATION_LIMIT_MAX}`});
298→    }
299→
300→    // Fetch a generous amount from both tables, then merge and paginate
301→    const fetchLimit = parsedLimit + 1;
302→
303→    let journalQuery = supabase
304→    .from('notifications')
305→    .select(NOTIFICATION_JOURNAL_SELECT)
306→    .eq('receiver_id', userId)
307→    .order('created_at', {ascending: false})
308→    .order('id', {ascending: false})
309→    .limit(fetchLimit)
310→
311→    let opinionQuery = supabase
312→    .from('notification_opinions')
313→    .select(NOTIFICATION_OPINION_SELECT)
314→    .eq('receiver_id', userId)
315→    .order('created_at', {ascending: false})
316→    .order('id', {ascending: false})
317→    .limit(fetchLimit)
318→
319→    if(before){
320→        journalQuery = journalQuery.lt('created_at', before);
321→        opinionQuery = opinionQuery.lt('created_at', before);
322→    }
323→
324→    const [journalResult, opinionResult] = await Promise.all([journalQuery, opinionQuery]);
325→
326→    if(journalResult.error){
327→        console.error('error while fetching data from notification table:', journalResult.error);
328→        return res.status(500).json({error: 'error fetching data from notification table'});
329→    }
330→    if(opinionResult.error){
331→        console.error('error while fetching data from notification_opinions table:', opinionResult.error);
332→        return res.status(500).json({error: 'error fetching data from notification_opinions table'});
333→    }
334→
335→    const journalNotifs = (journalResult.data || []).map(n => ({...n, source: 'journal'}));
336→    const opinionNotifs = (opinionResult.data || []).map(n => ({...n, source: 'opinion'}));
337→
338→    // Merge and sort by created_at descending
339→    const merged = [...journalNotifs, ...opinionNotifs]
340→        .sort((a, b) => new Date(b.created_at) - new Date(a.created_at));
341→
342→    // Likes/bookmarks lookup only for journal notifications
343→    const journalIds = [...new Set(
344→        merged
345→            .filter((n) => n.source === 'journal')
346→            .map((n) => n.journal_id)
347→            .filter(Boolean)
348→    )];
349→
350→    let hasLikedResult = [];
351→    let hasBookMarkedResult = [];
352→    if(journalIds.length > 0){
353→        const [hasLiked, hasBookMarked] = await Promise.all([
354→            supabase.from('likes').select('journal_id').in('journal_id', journalIds).eq('user_id', userId),
355→            supabase.from('bookmarks').select('journal_id').in('journal_id', journalIds).eq('user_id', userId)
356→        ]);
357→
358→        if(hasLiked.error || hasBookMarked.error){
359→            console.error('supabase error while fetching data:', hasLiked.error || hasBookMarked.error);
360→        }
361→        hasLikedResult = hasLiked.data || [];
362→        hasBookMarkedResult = hasBookMarked.data || [];
363→    }
364→
365→    const userHasLikedSet = new Set(hasLikedResult.map((likes) => likes.journal_id));
366→    const userHasBookmarkedSet = new Set(hasBookMarkedResult.map((bookmarks) => bookmarks.journal_id));
367→
368→    const formatted = merged.map((notif) => decorateNotificationMedia({
369→        ...notif,
370→        hasLiked: notif.source === 'journal' ? userHasLikedSet.has(notif.journal_id) : false,
371→        hasBookMarked: notif.source === 'journal' ? userHasBookmarkedSet.has(notif.journal_id) : false
372→    }))
373→
374→    const hasMore = formatted.length > parsedLimit;
375→    const slicedData = hasMore ? formatted.slice(0, parsedLimit) : formatted;
376→
377→    return res.status(200).json(
378→        {
379→            hasMore: hasMore,
380→            data: slicedData,
381→        }
382→    )
383→
384→})
