export const updateJournal = (token, body) =>
    authedFormRequest(token, 'POST', '/update-journal', body, 'failed to update journal');

export const deleteJournalImage = async (token, url) => {
    const data = { filepath: [] };
    if (url.length) {
        url.forEach(element => {
            data.filepath.push(element.split('/journal-images/').pop());
        });
    }
    return authedJsonRequest(token, 'POST', '/delete-journal-images', data, 'failed to delete journal images');
};

export const getFollowingFeed = (token, cursor = null, limit = 5) => {
    const path = cursor
        ? `/journals/following?limit=${limit}&before=${cursor}`
        : `/journals/following?limit=${limit}`;
    return authedGet(token, path, 'Failed to fetch following feed');
};

export const getForYouFeed = (token, offset = 0, limit = 5) =>
    authedGet(token, `/journals/for-you?limit=${limit}&offset=${offset}`, 'Failed to fetch for-you feed');

export const getInterestSections = (token) =>
    authedGet(token, '/explore/interests', 'Failed to fetch interest sections');

export const getJournals = async (cursor = null, limit = 5, userId) => {
    let path = cursor
        ? `/journals?limit=${limit}&before=${cursor}`
        : `/journals?limit=${limit}`;
    if (userId) path += `&userId=${userId}`;
    return publicGet(path, 'Failed to fetch journals');
};

export const getMonthlyHottestJournals = (userId, limit = 10) => {
    const parsedLimit = Number(limit);
    if (Number.isNaN(parsedLimit) || parsedLimit < 1 || parsedLimit > 10) {
        throw new Error('limit should be an integer between 1 and 10');
    }
    let path = `/journals/hottest-monthly?limit=${parsedLimit}`;
    if (userId) path += `&userId=${encodeURIComponent(userId)}`;
    return publicGet(path, 'failed to fetch monthly hottest journals');
};

export const searchUsers = (query, limit = 10) => {
    const q = typeof query === 'string' ? query.trim() : '';
    if (!q) return Promise.resolve({ data: [], hasMore: false });
    return publicGet(`/users/search?query=${encodeURIComponent(q)}&limit=${limit}`, 'failed to search users');
};

export const searchFollowingUsers = (token, query = '', limit = 10) => {
    const params = new URLSearchParams({ limit: String(limit) });
    if (query) params.set('query', query);
    return authedGet(token, `/users/following/search?${params}`, 'failed to search following users');
};

export const searchJournals = (query, limit = 10, userId) => {
    const q = typeof query === 'string' ? query.trim() : '';
    if (!q) return Promise.resolve({ data: [], hasMore: false, mode: 'keyword' });
    let path = `/journals/search?query=${encodeURIComponent(q)}&limit=${limit}`;
    if (userId) path += `&userId=${encodeURIComponent(userId)}`;
    return publicGet(path, 'failed to search journals');
};

export const getJournalById = (journalId, userId, options = {}) => {
    if (!journalId) throw new Error('journalId is required');
    const params = new URLSearchParams();
    if (userId) params.set('userId', String(userId));
    if (options.includeRepostContent) params.set('includeRepostContent', 'true');
    const qs = params.toString();
    const path = qs
        ? `/journal/${encodeURIComponent(journalId)}?${qs}`
        : `/journal/${encodeURIComponent(journalId)}`;
    return publicGet(path, 'failed to fetch journal');
};

