402→export const useReactionMutation = (session, userId) => {
403→    const queryClient = useQueryClient();
404→    const inFlightRef = useRef(new Set());
405→
406→    const mutation = useMutation({
407→        mutationFn: (data) => toggleReaction(session?.access_token, data),
408→
409→        onMutate: async (data) => {
410→            queryClient.cancelQueries({ queryKey: ['journals'] });
411→            queryClient.cancelQueries({ queryKey: ['journals-following'] });
412→            queryClient.cancelQueries({ queryKey: ['journals-for-you'] });
413→            queryClient.cancelQueries({ queryKey: ['userJournals'] });
414→            queryClient.cancelQueries({ queryKey: ['visitedProfileJournals'] });
415→
416→            const previousData = [
417→                ...queryClient.getQueriesData({ queryKey: ['journals'] }),
418→                ...queryClient.getQueriesData({ queryKey: ['journals-following'] }),
419→                ...queryClient.getQueriesData({ queryKey: ['journals-for-you'] }),
420→                ...queryClient.getQueriesData({ queryKey: ['userJournals'] }),
421→                ...queryClient.getQueriesData({ queryKey: ['visitedProfileJournals'] }),
422→            ];
423→
424→            const updater = (journal) => {
425→                if (journal.id !== data.journalId) return journal;
426→
427→                const currentReaction = journal?.user_reaction;
428→                const currentCount = normalizeCount(journal?.reaction_count?.[0]?.count);
429→
430→                let nextReaction;
431→                let nextCount;
432→
433→                if (currentReaction === data.reactionType) {
434→                    // Toggle off
435→                    nextReaction = null;
436→                    nextCount = Math.max(currentCount - 1, 0);
437→                } else if (currentReaction) {
438→                    // Switch reaction (count stays same)
439→                    nextReaction = data.reactionType;
440→                    nextCount = currentCount;
441→                } else {
442→                    // New reaction
443→                    nextReaction = data.reactionType;
444→                    nextCount = currentCount + 1;
445→                }
446→
447→                return {
448→                    ...journal,
449→                    user_reaction: nextReaction,
450→                    reaction_count: [{ count: nextCount }],
451→                };
452→            };
453→
454→            queryClient.setQueriesData({ queryKey: ['journals'] }, (old) => updateInfiniteJournalsCache(old, updater));
455→            queryClient.setQueriesData({ queryKey: ['journals-following'] }, (old) => updateInfiniteJournalsCache(old, updater));
456→            queryClient.setQueriesData({ queryKey: ['journals-for-you'] }, (old) => updateInfiniteJournalsCache(old, updater));
457→            queryClient.setQueriesData({ queryKey: ['userJournals'] }, (old) => updateInfiniteJournalsCache(old, updater));
458→            queryClient.setQueriesData({ queryKey: ['visitedProfileJournals'] }, (old) => updateInfiniteJournalsCache(old, updater));
459→
460→            return { previousData };
461→        },
462→
463→        onError: (err, data, context) => {
464→            context?.previousData?.forEach(([key, value]) => {
465→                queryClient.setQueryData(key, value);
466→            });
467→        },
468→
469→    });
470→
471→    const guardedMutate = (variables, options) => {
472→        const journalKey = toJournalKey(variables?.journalId);
473→        if (journalKey && inFlightRef.current.has(journalKey)) return;
474→
475→        if (journalKey) inFlightRef.current.add(journalKey);
476→
477→        mutation.mutate(variables, {
478→            ...options,
479→            onSettled: (data, error, vars, context) => {
480→                if (journalKey) inFlightRef.current.delete(journalKey);
481→                options?.onSettled?.(data, error, vars, context);
482→            },
483→        });
484→    };
485→
486→    return { ...mutation, mutate: guardedMutate };
487→}
